const cluster = require('node:cluster');

const { getAvailableConcurrency } = require('@meli/node-infra');

const {
  CRON_EVENT_TYPE,
  CRON_WORKER_READY_TYPE,
} = require('../../constants/cron');

/**
 * @typedef {import('cluster').Worker} Worker
 * @param {{onOnline: () => void, onMessage: (key: string, data: any) => Promise<void>, onNewOnlineWorker: (worker: Worker) => void }} options
 */
function handleCluster({ onOnline, onMessage, onNewOnlineWorker }) {
  if (cluster.isPrimary) {
    const availableConcurrency = getAvailableConcurrency();

    let onlineWorkers = 0;

    cluster.on('online', () => {
      onlineWorkers += 1;

      if (onlineWorkers === availableConcurrency) {
        onOnline();
      }
    });

    cluster.on('message', (worker, message) => {
      if (message?.type === CRON_WORKER_READY_TYPE) {
        onNewOnlineWorker(worker);
      }
    });
  } else if (cluster.isWorker) {
    process.on('message', async ({ type, data }) => {
      if (type === CRON_EVENT_TYPE) {
        await onMessage(data.key, data.value);
      }
    });

    process.send({ type: CRON_WORKER_READY_TYPE });
  }
}

/**
 * @param {{key: string, value: any}} data
 */
function handleWorkerSend(data) {
  if (!cluster.isPrimary) {
    return;
  }

  Object.values(cluster.workers).forEach((worker) =>
    worker.send({
      type: CRON_EVENT_TYPE,
      data,
    }),
  );
}

module.exports = {
  handleCluster,
  handleWorkerSend,
};
